/**
 * Project Write Retry — PermissionDenied Hook
 *
 * When auto mode denies a Write/Edit to a file inside the project directory
 * (excluding sensitive dirs), return {retry: true}.
 *
 * Reuses containment logic from auto-approve-project-writes.ts.
 *
 * SEC: Respects EXCLUDED_DIRS (node_modules, .git, dist, etc.)
 * SEC: Never retries writes outside project or added dirs
 *
 * CC 2.1.88 Compliant: PermissionDenied hook, returns {retry: true}
 * @hook PermissionDenied[Write|Edit]
 * @since v7.27.0
 * @see #1210
 */

import type { HookInput, HookResult } from '../types.js';
import { outputSilentSuccess, logHook, getProjectDir } from '../lib/common.js';
import { isInsideDir, hasExcludedDir, resolveRealPath } from '../lib/path-containment.js';
import { isAbsolute, resolve } from 'node:path';

const HOOK_NAME = 'project-write-retry';

function outputRetry(reason: string): HookResult {
  return {
    continue: true,
    suppressOutput: true,
    hookSpecificOutput: {
      hookEventName: 'PermissionDenied',
      retry: true,
      additionalContext: `[PermissionDenied retry] Write was incorrectly denied: ${reason}`,
    },
  };
}

export function projectWriteRetry(input: HookInput): HookResult {
  let filePath = input.tool_input.file_path || '';
  const projectDir = input.project_dir || getProjectDir();

  if (!filePath) {
    return outputSilentSuccess();
  }

  logHook(HOOK_NAME, `Evaluating denied write to: ${filePath}`);

  // CC >= 2.1.88: file_path always absolute for Write/Edit/Read. Kept for CC < 2.1.88 compat.
  if (!isAbsolute(filePath)) {
    filePath = resolve(projectDir, filePath);
  }

  // SEC: Resolve symlinks to prevent bypass attacks (ME-001 / PD-001)
  filePath = resolveRealPath(filePath, projectDir);

  // Check all root directories: project + /add-dir dirs
  const rootDirs = [projectDir, ...(input.added_dirs ?? [])];

  for (const rootDir of rootDirs) {
    if (!isInsideDir(filePath, rootDir)) continue;

    if (hasExcludedDir(filePath)) {
      logHook(HOOK_NAME, `File in excluded directory — not retrying`);
      return outputSilentSuccess();
    }

    const label = rootDir === projectDir ? 'project directory' : `added dir ${rootDir}`;
    logHook(HOOK_NAME, `File inside ${label} — retrying`);
    return outputRetry(`file is inside ${label}`);
  }

  logHook(HOOK_NAME, 'File outside project — not retrying');
  return outputSilentSuccess();
}
