/**
 * Safe Command Retry — PermissionDenied Hook
 *
 * When auto mode denies a Bash command that matches known-safe patterns,
 * return {retry: true} so the model can re-attempt.
 *
 * Reuses SAFE_PATTERNS from auto-approve-safe-bash.ts.
 * Only retries commands that are genuinely safe (read-only, no data loss).
 *
 * SEC: Never blindly retry all denials. Only retry known-safe patterns.
 * SEC: Compound commands are NOT retried (same guard as auto-approve).
 *
 * CC 2.1.88 Compliant: PermissionDenied hook, returns {retry: true}
 * @hook PermissionDenied[Bash]
 * @since v7.27.0
 * @see #1209
 */

import type { HookInput, HookResult } from '../types.js';
import { outputSilentSuccess, logHook } from '../lib/common.js';
import { isCompoundCommand, normalizeSingle } from '../lib/normalize-command.js';
import { REJECT_PATTERNS } from '../lib/bash-patterns.js';

const HOOK_NAME = 'safe-command-retry';

/**
 * Safe patterns that warrant an automatic retry when denied.
 * Subset of SAFE_PATTERNS from auto-approve-safe-bash.ts — only the safest.
 * Read-only commands only. No git checkout, no package managers that install.
 */
const RETRY_SAFE_PATTERNS: RegExp[] = [
  // Git read-only operations
  /^git (status|log|diff|branch|show|fetch|remote|tag)\b/,

  // Basic shell read-only
  /^ls(\s|$)/,
  /^pwd$/,
  /^cat\s/,
  /^head\s/,
  /^tail\s/,
  /^wc\s/,
  /^find\s/,
  /^which\s/,
  /^type\s/,
  /^env$/,
  /^printenv/,

  // Package manager read-only
  /^npm (list|ls|outdated|audit)\b/,
  /^pnpm (list|ls|outdated|audit)\b/,
  /^yarn (list|outdated|audit|info|why)\b/,

  // Docker read-only
  /^docker (ps|images|logs|inspect)\b/,

  // GitHub CLI read-only
  /^gh (issue|pr|repo|workflow) (list|view|status)\b/,

  // Test/lint commands
  /^npm run (test|lint|typecheck|format)\b/,
  /^pytest\b/,
];

// REJECT_PATTERNS imported from lib/bash-patterns.ts (unified source)

function outputRetry(reason: string): HookResult {
  return {
    continue: true,
    suppressOutput: true,
    hookSpecificOutput: {
      hookEventName: 'PermissionDenied',
      retry: true,
      additionalContext: `[PermissionDenied retry] Command was incorrectly denied: ${reason}`,
    },
  };
}

export function safeCommandRetry(input: HookInput): HookResult {
  const command = input.tool_input.command || '';

  if (!command) {
    return outputSilentSuccess();
  }

  logHook(HOOK_NAME, `Evaluating denied command: ${command.slice(0, 80)}`);

  // SEC: Never retry compound commands
  if (isCompoundCommand(command)) {
    logHook(HOOK_NAME, 'Compound command — not retrying');
    return outputSilentSuccess();
  }

  const normalized = normalizeSingle(command);

  // SEC: Check reject patterns first
  for (const pattern of REJECT_PATTERNS) {
    if (pattern.test(normalized)) {
      logHook(HOOK_NAME, `Matches reject pattern — not retrying`);
      return outputSilentSuccess();
    }
  }

  // Check against safe retry patterns
  for (const pattern of RETRY_SAFE_PATTERNS) {
    if (pattern.test(normalized)) {
      logHook(HOOK_NAME, `Matches safe pattern: ${pattern} — retrying`);
      return outputRetry(`matches safe read-only pattern: ${pattern}`);
    }
  }

  logHook(HOOK_NAME, 'No safe pattern matched — not retrying');
  return outputSilentSuccess();
}
